var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"NERVIA_CORRUPT_NULL_NULL","text":{"KOREA":"캬아아███!!","JPN":"キャア███！！","ENG":"Kya███!","TWN":"咳啊啊███！！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NERVIA_CORRUPT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"......또 부활한 건가? 대체 얼마나 쓰러트려야 하는 거야?","JPN":"……また復活したか！　いったい何回倒せばいいの？","ENG":"Did she come back to life again? How many times do I have to defeat her?","TWN":"……又復活了嗎？到底要打倒幾次才行？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"이래선...... 리플레이서 녀석들과 다를 게 없잖아.","JPN":"このままじゃ……リプレイサーの奴らと変わらない。","ENG":"She's like... the Replacers.","TWN":"這樣的話……跟克隆集團的傢伙沒什麼兩樣。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"이 녀석이 리플레이서와 관련이 있을 리는 없는데, 대체 어떻게......","JPN":"こいつがリプレイサーと関連しているはずがない。でもどうして……","ENG":"But she couldn't possibly have anything to do with them... So how come...","TWN":"這傢伙不可能跟克隆集團有關，到底為什麼……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"크윽!","JPN":"くっ！","ENG":"Hngh!","TWN":"呃啊！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_BOOM"},{"id":"L10_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"네가 돕지 않으면 그녀는 패배할 거다, 레이.","JPN":"お前が助けないと彼女は負けてしまうぞ、レイ。","ENG":"She will be defeated without your help, Ray.","TWN":"如果你不幫忙的話，她一定會失敗的，雷伊。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"그렇게 되면...... 우리는 또다시 모든 희망을 잃고 공허 속을 헤매야 하겠지.","JPN":"そうなると……我々はまたすべての希望を失い、空虚の中を彷徨うことになるだろう。","ENG":"And if it comes to that... We shall lose all hope again, and wander aimlessly through the void.","TWN":"那樣的話……我們又要失去所有希望，在虛空中遊蕩。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"이제는 모든 것들을 제자리로 돌릴 때가 됐어.","JPN":"今はすべてを元のあるべき場所に戻す時となった。","ENG":"It is time to return everything to its rightful place.","TWN":"現在到了讓所有東西歸位的時候了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"레이, 네 힘이 필요하다.","JPN":"レイ、お前の力が必要だ。","ENG":"She needs your help, Ray.","TWN":"雷伊，我需要你的力量。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_NULL","text":{"KOREA":"......이러지 마.","JPN":"……やめて。","ENG":"Don't do this to me.","TWN":"……不要這樣。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_NULL","text":{"KOREA":"제발 부탁이야. 난 그러고 싶지 않아.","JPN":"お願い、僕は嫌だよ。","ENG":"Please. I really don't want to.","TWN":"求求你，我真的不想這樣。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"언제까지 현실을 외면하기만 할 거냐!","JPN":"いつまで現実から目を背けるつもりだ？","ENG":"How long will you continue to turn a blind eye to reality?","TWN":"你想逃避現實到什麼時候？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L22_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"우리 모두가...... 네게 어떤 기대를 걸고 있는지 알고 있잖아.","JPN":"私たちが……お前にどれだけ期待しているかわかっているはずだ。","ENG":"All of us are counting on you... You know that.","TWN":"你清楚我們所有人……對你的期待是什麼。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L23_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_NULL","text":{"KOREA":"난...... 난 더 이상 기대 받고 싶지 않아!","JPN":"僕は……僕はもう期待なんかされたくないんだ！","ENG":"I... I don't want anyone to count on me anymore!","TWN":"我……我再也不想受到期待了！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L24_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_NULL","text":{"KOREA":"난 실패자라고! 내게 기회 같은 건 없어!","JPN":"僕は失敗者だから！　チャンスなどない！","ENG":"I'm a failure! There is no second chance for me!","TWN":"我是失敗者！對我來說沒有機會了！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_NULL","text":{"KOREA":"그런데 대체 왜 날 계속 괴롭히는 거야? 이제 제발 그만 내버려 둬!","JPN":"なのにどうして僕にずっと付きまとう？　もう放っておいて！","ENG":"Why do you keep harassing me? Just leave me in peace now!","TWN":"你們為什麼還糾纏我？拜託，放過我吧！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"오늘 여기까지 따라왔던 건 너도 각오를 했기 때문 아니었나?","JPN":"今日ここまでついてきたのは、お前も覚悟したからじゃないのか？","ENG":"But didn't you come along today because you've finally made up your mind?","TWN":"今天你能跟到這裡來，不是說明你已經有覺悟了嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_NULL","text":{"KOREA":"그런 거 아니야...... 난 그저 억지로 끌려온 것뿐이라고.","JPN":"違うよ……僕は無理やり連れてこられただけだよ。","ENG":"That's not why... I was dragged here against my will.","TWN":"不是這樣……我只是被硬拉來的。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L28_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L29_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"다이브 직후에 널 걱정하던 내게 그녀가 말하더군.","JPN":"ダイブ直後、お前のことを心配していた私にこう言った。","ENG":"Right after the Dive, she told me not to worry about you.","TWN":"在躍入後，她跟我說過，"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L30_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"널 믿고 지켜 보라고, 넌 결국 옳은 선택을 할 거라고.","JPN":"お前を信じて見守ってと、お前は結局正しい選択をすると。","ENG":"She said that I should have faith in you and you'd ultimately make the right decision.","TWN":"說要我更加信任你，並說你最終會做出正確的選擇。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L31_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"레이, 네가 했던 맹세를 기억해라. 의무로부터 도망치지 마.","JPN":"レイ、自らの誓いを忘れるな。義務から逃げるな。","ENG":"Remember your oath, Ray. Don't flee from your duties.","TWN":"雷伊，記住你的誓言吧。不要逃避你的義務。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"그러지 않으면, 지금까지 있었던 그 모든 희생은 무가치해질 테니까.","JPN":"そうしないと、これまでのすべての犠牲は無価値なものになる。","ENG":"Otherwise, all the sacrifices thus far will have been in vain.","TWN":"不然至今為止的所有犧牲都將變得毫無意義。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_NULL","text":{"KOREA":"차라리...... 알렌이 내 힘을 넘겨 받으면...... 그러면......","JPN":"いっそ……アレンが僕の力を譲り受けたら……そうすれば……","ENG":"What if... you got my powers instead, Allen... If that was possible...","TWN":"不如……艾倫你接受我的力量……那樣的話……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"그럴 수 없다는 건 너도 잘 알고 있을 텐데.","JPN":"それはできないというのは、お前も知っているはずだ。","ENG":"You know full well that is out of the question.","TWN":"你也知道那是不可能的。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L38_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"그녀의 숙명을 해방시켜서 제물로 완성하는 건......","JPN":"彼女の宿命を解放させて生贄として完成させるのは……","ENG":"You are the only one among us...","TWN":"解放她的宿命，讓她成為完整的祭品……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"우리 중에서 오직 너만이 할 수 있는 일이야.","JPN":"我々の中でもお前だけができることだ。","ENG":"who can free her from her destiny and complete her as the sacrifice.","TWN":"在我們當中只有你能做到。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};